INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('fire-eq-eng-moex-01123', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關「建築技術規則」規定之敘述，何者錯誤？', '["不燃材料：經中央主管建築機關認定符合耐燃一級之不因火熱引起燃燒、熔化、破裂變形及產生有害氣 體之材料", "耐火板：經中央主管建築機關認定符合耐燃二級之材料", "耐燃材料：經中央主管建築機關認定符合耐燃三級之材料", "阻熱性：在標準耐火試驗條件下，建築構造當其四面受火時，能在一定時間內，其非加熱面溫度不超過 規定值之能力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01124', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關「緊急廣播設備用揚聲器認可基準」規定之敘述，何者錯誤？', '["頻率特性試驗：錐型揚聲器之額定頻率範圍上限值需達8kHz以上，為功能正常", "頻率特性試驗：號角型揚聲器頻率區域之最高頻率範圍上限值需達4kHz以上，為功能正常", "連續鳴動試驗：以額定電壓之第二信號音執行連續鳴動測試12小時，音壓、音質等無異常音或雜音等情 況，為功能正常", "環境溫度試驗：放置於-10℃及40℃之環境中各12小時，再置於常溫中，以額定功率之第二信號音執行 鳴動測試1分鐘，音壓、音質等無異常音或雜音等情況，為功能正常"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01125', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依耐燃電纜認可基準之規定，下列何者屬「高壓電纜」？', '["電纜耐電壓超過200V者", "電纜耐電壓超過300V者", "電纜耐電壓超過500V者", "電纜耐電壓超過600V者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01126', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品試驗方法及判定基準之規定，有關易燃性液體依物質引火性進行判定之判定基準，下列何 者錯誤？', '["閃火點≦-20℃且起始沸點＜40℃者，為第一石油類", "21℃≦閃火點＜70℃者，為第二石油類（非水溶性液體）", "70℃≦閃火點＜200℃者，為第三石油類（非水溶性液體）", "閃火點≧200℃者，為第四石油類"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01127', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依可燃性高壓氣體儲存場所防爆牆設置基準規定，防爆牆長度應超過設置方位儲存場所建築物牆面長度。 其牆腳與儲存場所建築物之距離不得少於多少公尺？', '["1公尺", "2公尺", "3公尺", "5公尺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01128', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防安全設備檢修專業機構管理辦法規定，檢修機構合格證書記載事項變更時，應於幾日內向內政部申 請變更登記？', '["10日", "15日", "20日", "30日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01129', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防安全設備檢修專業機構管理辦法規定，檢修機構聘用、資遣、解聘消防設備師或消防設備士，應於 幾日內，報請內政部備查？', '["10日", "15日", "20日", "30日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01130', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備檢修及申報作業基準規定，下列有關固定式泡沫滅火設備（低發泡）綜合檢查之 敘述，何者錯誤？', '["於檢查類似醫院之場所，因切換緊急電源可能造成困擾時，得使用常用電源檢查", "測定發泡倍率時，使用其所採取之泡水溶液，利用糖度計法或比色計法，測其混合比率", "檢查方法中，每次選擇全部放射區域數之30％ 以上之放射區域，進行逐區放水試驗，測其放射分布及放 射壓力", "在進行泡沫放射檢查時，其發泡倍率應在5倍以上，其混合比率應為設計時之稀釋容量濃度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01131', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依液化石油氣容器認可作業及管理要點規定，取得型式認可廠商之製造設施均應由專職人員擔任製造作業， 確實紀錄液化石油氣容器製造相關資料，並至少保存幾年？', '["5年", "4年", "3年", "2年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01132', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備檢修及申報作業基準規定，下列有關室外消防栓設備綜合檢查敘述，何者錯誤？', '["判定方法中，放水量應在350l/min以上", "判定方法中，放水壓力應在2.5kgf/cm2以上6kgf/cm2以下", "檢查方法中，選擇任二具室外消防栓做放水試驗", "檢查方法中，測量瞄子直線放水之壓力時，將壓力表之進水口，放置於瞄子前端瞄子口徑的三分之一距 離處，讀取壓力表的指示值"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
